import type React from "react";

import { cn } from "../utils/cn";

type MonitorMetricDisplayVariant = "primary" | "regular";
type OEETargetStatus = "on-target" | "off-target" | "at-risk" | "none";

interface MetricTileProps extends React.ComponentProps<"div"> {
  /** The metric value to display. When undefined, displays the placeholder. */
  value?: number | string;
  /** Unit of measurement (defaults to '%'). */
  unit?: string;
  /** Text shown when value is undefined (defaults to 'N/A'). */
  placeholder?: string;
  /** Display variant — 'primary' for larger OEE tile, 'regular' for A/P/Q. */
  variant?: MonitorMetricDisplayVariant;
  /** Target status — affects text colour in primary variant. */
  status?: OEETargetStatus;
  /** Whether the display is disabled (greyed out). */
  disabled?: boolean;
  /** Label displayed above the value (convenience prop). */
  label?: string;
  /** Size hint — kept for backward-compat with MetricCard consumers. */
  size?: "sm" | "md" | "lg";
}

function getValueSizeClass(
  displayValue: string | number,
  variant: MonitorMetricDisplayVariant,
) {
  if (typeof displayValue === "string" && displayValue.length > 4) {
    return "text-xl pb-1";
  }
  if (variant === "primary") {
    return "text-3xl";
  }
  return "text-2xl";
}

function getUnitSizeClass(variant: MonitorMetricDisplayVariant) {
  return variant === "primary" ? "text-2xl" : "text-lg";
}

function getTextColorClass(
  variant: MonitorMetricDisplayVariant,
  status: OEETargetStatus,
) {
  if (variant === "primary") {
    return status === "on-target" ? "text-success-700" : "text-grey-1100";
  }
  return "text-grey-900";
}

/**
 * Metric value + unit display mirroring `MonitorMetricDisplay.vue`.
 *
 * - Value sizing adapts to character count (>4 chars = text-xl)
 * - Unit displayed next to value (not below)
 * - Bold font for values
 * - leading-none for compact layout
 */
function MetricTile({
  value,
  unit = "%",
  placeholder = "N/A",
  variant = "regular",
  status = "none",
  disabled = false,
  label,
  size: _size,
  className,
  children,
  ...props
}: MetricTileProps) {
  const hasValue = value !== undefined && value !== null;
  const displayValue = hasValue ? value : placeholder;
  const valueSizeClass = getValueSizeClass(displayValue, variant);
  const unitSizeClass = getUnitSizeClass(variant);
  const textColorClass = getTextColorClass(variant, status);

  return (
    <div data-slot="metric-tile" className={cn(className)} {...props}>
      {label && (
        <span
          data-slot="metric-tile-label"
          className="text-xs text-muted-foreground"
        >
          {label}
        </span>
      )}
      <div className={cn("flex grow items-start", textColorClass)}>
        <div
          className={cn(valueSizeClass, "font-bold leading-none", {
            "text-grey-500": disabled,
          })}
          data-testid="value"
        >
          {displayValue}
        </div>
        <div className={cn(unitSizeClass, "leading-none")} data-testid="unit">
          {hasValue ? unit : ""}
        </div>
        <div className="grow" />
      </div>
      {children}
    </div>
  );
}

export { MetricTile };
export type { MetricTileProps, MonitorMetricDisplayVariant };
